  1→/**
  2→ * Installation Component Tests - SKF Module
  3→ *
  4→ * Tests SKF module installation components in isolation:
  5→ * - Module.yaml structure validation
  6→ * - Agent YAML structure validation
  7→ * - Path references validation
  8→ * - Workflow existence verification
  9→ *
 10→ * These are deterministic unit tests that don't require full installation.
 11→ * Usage: node test/test-installation-components.js
 12→ */
 13→
 14→const path = require('node:path');
 15→const fs = require('node:fs/promises');
 16→const yaml = require('js-yaml');
 17→
 18→async function pathExists(filePath) {
 19→  try {
 20→    await fs.access(filePath);
 21→    return true;
 22→  } catch {
 23→    return false;
 24→  }
 25→}
 26→
 27→// ANSI colors
 28→const colors = {
 29→  reset: '\u001B[0m',
 30→  green: '\u001B[32m',
 31→  red: '\u001B[31m',
 32→  yellow: '\u001B[33m',
 33→  cyan: '\u001B[36m',
 34→  dim: '\u001B[2m',
 35→};
 36→
 37→let passed = 0;
 38→let failed = 0;
 39→
 40→/**
 41→ * Test helper: Assert condition
 42→ */
 43→function assert(condition, testName, errorMessage = '') {
 44→  if (condition) {
 45→    console.log(`${colors.green}✓${colors.reset} ${testName}`);
 46→    passed++;
 47→  } else {
 48→    console.log(`${colors.red}✗${colors.reset} ${testName}`);
 49→    if (errorMessage) {
 50→      console.log(`  ${colors.dim}${errorMessage}${colors.reset}`);
 51→    }
 52→    failed++;
 53→  }
 54→}
 55→
 56→/**
 57→ * Test Suite
 58→ */
 59→async function runTests() {
 60→  console.log(`${colors.cyan}========================================`);
 61→  console.log('SKF Installation Component Tests');
 62→  console.log(`========================================${colors.reset}\n`);
 63→
 64→  const projectRoot = path.join(__dirname, '..');
 65→
 66→  // ============================================================
 67→  // Test 1: Module.yaml Structure
 68→  // ============================================================
 69→  console.log(`${colors.yellow}Test Suite 1: Module Configuration${colors.reset}\n`);
 70→
 71→  try {
 72→    const moduleYamlPath = path.join(projectRoot, 'src/module.yaml');
 73→    const moduleYaml = yaml.load(await fs.readFile(moduleYamlPath, 'utf8'));
 74→
 75→    assert(moduleYaml.code === 'skf', 'module.yaml has correct code: skf');
 76→    assert(typeof moduleYaml.name === 'string' && moduleYaml.name.length > 0, 'module.yaml has name');
 77→    assert(typeof moduleYaml.description === 'string' && moduleYaml.description.length > 0, 'module.yaml has description');
 78→    assert(typeof moduleYaml.default_selected === 'boolean', 'module.yaml has boolean default_selected');
 79→  } catch (error) {
 80→    assert(false, 'module.yaml loads and validates', error.message);
 81→  }
 82→
 83→  console.log('');
 84→
 85→  // ============================================================
 86→  // Test 2: SKF Agent YAML Structure
 87→  // ============================================================
 88→  console.log(`${colors.yellow}Test Suite 2: SKF Agent Structure${colors.reset}\n`);
 89→
 90→  try {
 91→    const skfAgentPath = path.join(projectRoot, 'src/agents/forger.agent.yaml');
 92→
 93→    if (await pathExists(skfAgentPath)) {
 94→      const skfAgent = yaml.load(await fs.readFile(skfAgentPath, 'utf8'));
 95→
 96→      assert(skfAgent.agent !== undefined, 'forger.agent.yaml has agent root key');
 97→      assert(skfAgent.agent.metadata !== undefined, 'SKF agent has metadata section');
 98→      assert(skfAgent.agent.metadata.module === 'skf', 'SKF agent metadata has module: skf');
 99→      assert(skfAgent.agent.metadata.id.includes('_bmad/skf/'), 'SKF agent id references _bmad/skf/ path');
100→      assert(skfAgent.agent.persona !== undefined, 'SKF agent has persona section');
101→      assert(skfAgent.agent.critical_actions !== undefined, 'SKF agent has critical_actions');
102→      assert(skfAgent.agent.menu !== undefined, 'SKF agent has menu');
103→      assert(
104→        Array.isArray(skfAgent.agent.menu) && skfAgent.agent.menu.length === 13,
105→        'SKF agent menu has 13 entries (12 workflows + 1 status action)',
106→        `Found ${Array.isArray(skfAgent.agent.menu) ? skfAgent.agent.menu.length : 'non-array'}`,
107→      );
108→
109→      // Verify no foreign module references
110→      const yamlContent = await fs.readFile(skfAgentPath, 'utf8');
111→      assert(!yamlContent.includes('module: tea'), 'SKF agent has no module: tea references');
112→      assert(!yamlContent.includes('module: bmm'), 'SKF agent has no module: bmm references');
113→    } else {
114→      assert(false, 'SKF agent YAML exists', 'src/agents/forger.agent.yaml not found');
115→    }
116→  } catch (error) {
117→    assert(false, 'SKF agent structure validates', error.message);
118→  }
119→
120→  console.log('');
121→
122→  // ============================================================
123→  // Test 3: Knowledge Base Structure
124→  // ============================================================
125→  console.log(`${colors.yellow}Test Suite 3: Knowledge Base${colors.reset}\n`);
126→
127→  try {
128→    const skfIndexPath = path.join(projectRoot, 'src/knowledge/skf-knowledge-index.csv');
129→
130→    if (await pathExists(skfIndexPath)) {
131→      const csvContent = await fs.readFile(skfIndexPath, 'utf8');
132→      const lines = csvContent.trim().split('\n');
133→
134→      assert(lines.length >= 2, 'skf-knowledge-index.csv has header + at least 1 record', `Found ${lines.length} lines`);
135→      assert(lines[0].includes('id,name,description,tags,tier,fragment_file'), 'skf-knowledge-index.csv has correct header format');
136→    } else {
137→      assert(false, 'Knowledge index exists', 'src/knowledge/skf-knowledge-index.csv not found');
138→    }
139→  } catch (error) {
140→    assert(false, 'Knowledge base structure validates', error.message);
141→  }
142→
143→  console.log('');
144→
145→  // ============================================================
146→  // Test 4: Workflow Structure
147→  // ============================================================
148→  console.log(`${colors.yellow}Test Suite 4: Workflow Structure${colors.reset}\n`);
149→
150→  const workflowNames = [
151→    'setup-forge',
152→    'analyze-source',
153→    'brief-skill',
154→    'create-skill',
155→    'quick-skill',
156→    'create-stack-skill',
157→    'verify-stack',
158→    'refine-architecture',
159→    'update-skill',
160→    'audit-skill',
161→    'test-skill',
162→    'export-skill',
163→  ];
164→
165→  for (const workflowName of workflowNames) {
166→    const workflowPath = path.join(projectRoot, `src/workflows/${workflowName}/workflow.md`);
167→
168→    if (await pathExists(workflowPath)) {
169→      const content = await fs.readFile(workflowPath, 'utf8');
170→      assert(content.length > 0, `${workflowName}/workflow.md exists`);
171→    } else {
172→      assert(false, `${workflowName}/workflow.md exists`, `src/workflows/${workflowName}/workflow.md not found`);
173→    }
174→  }
175→
176→  console.log('');
177→
178→  // ============================================================
179→  // Test 5: Step-File Chain and Data File Validation
180→  // ============================================================
181→  console.log(`${colors.yellow}Test Suite 5: Step-File and Data File Validation${colors.reset}\n`);
182→
183→  const stepFileChains = {
184→    'verify-stack': {
185→      steps: [
186→        'step-01-init.md',
187→        'step-02-coverage.md',
188→        'step-03-integrations.md',
189→        'step-04-requirements.md',
190→        'step-05-synthesize.md',
191→        'step-06-report.md',
192→      ],
193→      data: ['coverage-patterns.md', 'feasibility-report-template.md', 'integration-verification-rules.md'],
194→    },
195→    'refine-architecture': {
196→      steps: [
197→        'step-01-init.md',
198→        'step-02-gap-analysis.md',
199→        'step-03-issue-detection.md',
200→        'step-04-improvements.md',
201→        'step-05-compile.md',
202→        'step-06-report.md',
203→      ],
204→      data: ['refinement-rules.md'],
205→    },
206→  };
207→
208→  for (const [workflow, files] of Object.entries(stepFileChains)) {
209→    for (const step of files.steps) {
210→      const stepPath = path.join(projectRoot, `src/workflows/${workflow}/steps-c/${step}`);
211→      const exists = await pathExists(stepPath);
212→      assert(exists, `${workflow}/steps-c/${step} exists`, `Missing step file: ${stepPath}`);
213→    }
214→    for (const dataFile of files.data) {
215→      const dataPath = path.join(projectRoot, `src/workflows/${workflow}/data/${dataFile}`);
216→      const exists = await pathExists(dataPath);
217→      assert(exists, `${workflow}/data/${dataFile} exists`, `Missing data file: ${dataPath}`);
218→    }
219→  }
220→
221→  console.log('');
222→
223→  // ============================================================
224→  // Summary
225→  // ============================================================
226→  console.log(`${colors.cyan}========================================`);
227→  console.log('Test Results:');
228→  console.log(`  Passed: ${colors.green}${passed}${colors.reset}`);
229→  console.log(`  Failed: ${colors.red}${failed}${colors.reset}`);
230→  console.log(`========================================${colors.reset}\n`);
231→
232→  if (failed === 0) {
233→    console.log(`${colors.green}✨ All installation component tests passed!${colors.reset}\n`);
234→    process.exit(0);
235→  } else {
236→    console.log(`${colors.red}❌ Some installation component tests failed${colors.reset}\n`);
237→    process.exit(1);
238→  }
239→}
240→
241→// Run tests
242→runTests().catch((error) => {
243→  console.error(`${colors.red}Test runner failed:${colors.reset}`, error.message);
244→  console.error(error.stack);
245→  process.exit(1);
246→});
